/** @file*/

#include <stdint.h>
#include <stdio.h>
#include "internal_nn_math.h"
#include "nds_nn_examples_cifar10_parameter.h"
#include "nds_nn_examples_cifar10_weights.h"

#include "nds_nn_softmax.h"
#include "nds_nn_activation.h"
#include "nds_nn_pooling.h"
#include "nds_nn_fully_connected.h"
#include "nds_nn_convolution.h"
#include "nds_nn_examples_cifar10_inputs.h"

#ifdef PF_COUNTER
#include "nds32_intrinsic.h"
#include "nds_pfcounter.h"
#endif

#include "test_util.h"

#ifdef CHECK
#include "nds_debug.h"
#endif

// include the input and weights

static q7_t conv1_wt[CONV1_IM_CH * CONV1_KER_DIM * CONV1_KER_DIM * CONV1_OUT_CH] = CONV1_WT;
static q7_t conv1_bias[CONV1_OUT_CH] = CONV1_BIAS;

static q7_t conv2_wt[CONV2_IM_CH * CONV2_KER_DIM * CONV2_KER_DIM * CONV2_OUT_CH] = CONV2_WT;
static q7_t conv2_bias[CONV2_OUT_CH] = CONV2_BIAS;

static q7_t conv3_wt[CONV3_IM_CH * CONV3_KER_DIM * CONV3_KER_DIM * CONV3_OUT_CH] = CONV3_WT;
static q7_t conv3_bias[CONV3_OUT_CH] = CONV3_BIAS;

static q7_t ip1_wt[IP1_DIM * IP1_OUT] = IP1_WT;
static q7_t ip1_bias[IP1_OUT] = IP1_BIAS;

/* Here the image_data should be the raw uint8 type RGB image in [RGB, RGB, RGB ... RGB] format */
uint8_t   image_data[CONV1_IM_CH * CONV1_IM_DIM * CONV1_IM_DIM] = IMG_DATA;
q7_t      output_data[IP1_OUT];

//vector buffer: max(im2col buffer,average pool buffer, fully connected buffer)
q7_t  col_buffer[2 * 5 * 5 * 32 * 2];
q15_t rgb_wt_buffer[CONV1_OUT_CH * (3 * CONV1_KER_DIM * CONV1_KER_DIM + 1)];


q7_t      scratch_buffer[32 * 32 * 10 * 4];


int main()
{
    enable_fs_and_vs();
    printf("start execution\n");
    /* start the execution */

    q7_t     *img_buffer1 = scratch_buffer;
    q7_t     *img_buffer2 = img_buffer1 + 32 * 32 * 32;

    /* input pre-processing */
    int mean_data[3] = INPUT_MEAN_SHIFT;
    unsigned int scale_data[3] = INPUT_RIGHT_SHIFT;
    int i;
    for (i = 0; i < 32*32*3; i += 3)
    {
#ifdef ENA_DSP_ISA
        img_buffer2[i] =   (q7_t)NDS_DSP_CLIPS( ((((int)image_data[i]   - mean_data[0]) << 7) + (0x1 << (scale_data[0] - 1)))
                                                >> scale_data[0], 8);
        img_buffer2[i+1] = (q7_t)NDS_DSP_CLIPS( ((((int)image_data[i+1] - mean_data[1]) << 7) + (0x1 << (scale_data[1] - 1)))
                                                >> scale_data[1], 8);
        img_buffer2[i+2] = (q7_t)NDS_DSP_CLIPS( ((((int)image_data[i+2] - mean_data[2]) << 7) + (0x1 << (scale_data[2] - 1)))
                                                >> scale_data[2], 8);
#else
        img_buffer2[i] =   (q7_t)NDS_ISA_CLIPS( ((((int)image_data[i]   - mean_data[0]) << 7) + (0x1 << (scale_data[0] - 1)))
                                                >> scale_data[0], 8);
        img_buffer2[i+1] = (q7_t)NDS_ISA_CLIPS( ((((int)image_data[i+1] - mean_data[1]) << 7) + (0x1 << (scale_data[1] - 1)))
                                                >> scale_data[1], 8);
        img_buffer2[i+2] = (q7_t)NDS_ISA_CLIPS( ((((int)image_data[i+2] - mean_data[2]) << 7) + (0x1 << (scale_data[2] - 1)))
                                                >> scale_data[2], 8);
#endif
    }

#ifdef CHECK
    FILE *checksum_log = fopen("cifar10.log", "w");
    dump_checksum(checksum_log, "init", "img_buffer2", img_buffer2, img_buffer2 + 32 * 32 * 8);
#endif

    /* enable un-alignment access */
    unsigned long reg;
#ifdef __riscv
    reg = __nds__mfsr(NDS_MMISC_CTL);
    reg |= (1 << 6);
    __nds__mtsr(reg, NDS_MMISC_CTL);
#else
    reg = __nds32__mfsr(NDS32_SR_MMU_CTL);
    reg |= (1 << 23);
    __nds32__mtsr(reg, NDS32_SR_MMU_CTL);
#endif

#if defined(PF_COUNTER) //&& !defined(FUNCTION_PF_ANALYZE)
    // unsigned int cycle=0, inst=0;
    printf("Start ... \n");
    startPFM;
#endif

    // conv1 img_buffer2 -> img_buffer1

#ifdef FUNCTION_PF_ANALYZE
    startPFM;
#endif
#ifdef FAST_VERSION
    riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias_fast(img_buffer2, CONV1_IM_DIM, conv1_wt, CONV1_OUT_CH, CONV1_KER_DIM, CONV1_PADDING,
                                CONV1_STRIDE, conv1_bias, CONV1_BIAS_LSHIFT, CONV1_OUT_RSHIFT, img_buffer1, CONV1_OUT_DIM,
                                (q15_t *) col_buffer, rgb_wt_buffer);
// #elif defined NEW_INST
//     nds_nn_conv_HWC_q7_RGB_fast2(img_buffer2, CONV1_IM_DIM, CONV1_IM_CH, conv1_wt, CONV1_OUT_CH, CONV1_KER_DIM, CONV1_PADDING,
//                                  CONV1_STRIDE, conv1_bias, CONV1_BIAS_LSHIFT, CONV1_OUT_RSHIFT, img_buffer1, CONV1_OUT_DIM,
//                                  (q15_t *) col_buffer, NULL);
